import json
import re

data = _items[0]["json"]
out = (data.get("stdout") or "").strip()
err = (data.get("stderr") or "").strip()

if not out:
    if err:
        agent_response = f"Ошибка выполнения: {err[:500]}"
    else:
        agent_response = "Скрипт ничего не вывел. Возможно, не хватило памяти или процесс был убит."

    return [{
        "json": {
            "output": agent_response,
            "status": "error",
            "stderr": err[:500] if err else None
        }
    }]

# ищем JSON в выводе
json_match = re.search(r'\{.*\}$', out, re.DOTALL)
if json_match:
    json_str = json_match.group()
else:
    json_str = out

try:
    parsed = json.loads(json_str)
except Exception as e:
    parsed = {
        "status": "parse_error",
        "parse_error": str(e),
        "raw": out[:500]
    }

if parsed.get("status") == "success":
    agent_response = parsed.get("summary")
else:
    err_msg = parsed.get("error") or parsed.get("parse_error") or "неизвестная ошибка"
    agent_response = f"Ошибка при обучении модели: {err_msg}"

# берём метрики с train для классификации
train_metrics = parsed.get("train_metrics", {})
if train_metrics:
    accuracy = train_metrics.get("accuracy", "N/A")
    precision = train_metrics.get("precision", "N/A")
    recall = train_metrics.get("recall", "N/A")
    f1 = train_metrics.get("f1", "N/A")
    roc_auc = train_metrics.get("roc_auc", "N/A")

    if isinstance(accuracy, (int, float)):
        accuracy = f"{accuracy:.4f}"
    if isinstance(precision, (int, float)):
        precision = f"{precision:.4f}"
    if isinstance(recall, (int, float)):
        recall = f"{recall:.4f}"
    if isinstance(f1, (int, float)):
        f1 = f"{f1:.4f}"
    if isinstance(roc_auc, (int, float)):
        roc_auc = f"{roc_auc:.4f}"
else:
    accuracy = precision = recall = f1 = roc_auc = "N/A"

return [
    {
        "json": {
            "output": agent_response,
            "status": parsed.get("status"),
            "summary": parsed.get("summary"),
            "candidate_path": parsed.get("candidate_path"),
            "train_metrics": {
                "accuracy": accuracy,
                "precision": precision,
                "recall": recall,
                "f1": f1,
                "roc_auc": roc_auc
            },
            "model_type": parsed.get("model_type"),
            "train_time_sec": parsed.get("train_time_sec"),
            "feature_count": parsed.get("feature_count"),
            "n_classes": parsed.get("n_classes"),
            "intercept": parsed.get("intercept")
        }
    }
]
